#include <stdio.h>
#include <string.h>

int main()
{
	char s[100], c[100], d[100];
	int i,j = 0, t;
	scanf("%s", s);

	//t copy
	for (i = 0; i < strlen(s); ++i)
	{

		if (s[i] != '+')
		{

			c[j] = s[i];
			j++;

		}
	}
	c[j] = '\0';

	//arrange
	for (j=0 ; j<(strlen(c)-1) ; j++)
	{

		for (i=0 ; i<(strlen(c)-1) ; i++)
		{

			if (c[i+1] < c[i])
			{

				t = c[i];
				c[i] = c[i + 1];
				c[i + 1] = t;
			}
		}
	}

	//print
	j = 0;
	for (i = 0; (i < strlen(c)); ++i)
	{
		d[j] = c[i];
		j++;
		if (i == strlen(c) - 1)
		{
			d[j] = '\0';
			break;
		}
		d[j] = '+';
		j++;

	}
	printf("%s\n", d);

	return 0;
}

